changeSet.sql:
ALTER TABLE clinlims.analyzer_results
    DROP CONSTRAINT IF EXISTS ck_analyzer_results_lis97_legacy_evidence_width;
ALTER TABLE clinlims.result
    DROP CONSTRAINT IF EXISTS ck_result_lis97_legacy_evidence_width;

CREATE OR REPLACE FUNCTION clinlims.reject_analyzer_evidence_rollback_archive_mutation()
RETURNS TRIGGER AS $BODY$
BEGIN
    RAISE EXCEPTION 'analyzer_evidence_rollback_archive is append-only'
        USING ERRCODE = '55000';
END;
$BODY$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS analyzer_evidence_rollback_archive_immutable
    ON clinlims.analyzer_evidence_rollback_archive;
CREATE TRIGGER analyzer_evidence_rollback_archive_immutable
    BEFORE UPDATE OR DELETE ON clinlims.analyzer_evidence_rollback_archive
    FOR EACH ROW EXECUTE FUNCTION clinlims.reject_analyzer_evidence_rollback_archive_mutation();

rollback.sql:
INSERT INTO clinlims.analyzer_evidence_rollback_archive (source_table, source_record_id, current_value, reference_range, abnormal_flag, evidence_digest) SELECT 'analyzer_results', ar.id, ar.result, ar.reference_range, ar.abnormal_flag, md5(jsonb_build_object( 'source_table', 'analyzer_results', 'source_record_id', ar.id, 'current_value', ar.result, 'reference_range', ar.reference_range, 'abnormal_flag', ar.abnormal_flag)::text) FROM clinlims.analyzer_results ar WHERE ar.reference_range IS NOT NULL OR ar.abnormal_flag IS NOT NULL ON CONFLICT (source_table, source_record_id, evidence_digest) DO NOTHING;
INSERT INTO clinlims.analyzer_evidence_rollback_archive (source_table, source_record_id, result_id, current_value, reference_range, abnormal_flag, evidence_digest) SELECT 'result', r.id, r.id, r.value, r.reference_range, r.abnormal_flag, md5(jsonb_build_object( 'source_table', 'result', 'source_record_id', r.id, 'result_id', r.id, 'current_value', r.value, 'reference_range', r.reference_range, 'abnormal_flag', r.abnormal_flag)::text) FROM clinlims.result r WHERE r.reference_range IS NOT NULL OR r.abnormal_flag IS NOT NULL ON CONFLICT (source_table, source_record_id, evidence_digest) DO NOTHING;
INSERT INTO clinlims.analyzer_evidence_rollback_archive (source_table, source_record_id, result_id, version_number, current_value, reference_range, abnormal_flag, evidence_digest) SELECT 'result_version', rv.id, rv.result_id, rv.version_number, rv.value, rv.reference_range, rv.abnormal_flag, md5(jsonb_build_object( 'source_table', 'result_version', 'source_record_id', rv.id, 'result_id', rv.result_id, 'version_number', rv.version_number, 'current_value', rv.value, 'reference_range', rv.reference_range, 'abnormal_flag', rv.abnormal_flag)::text) FROM clinlims.result_version rv WHERE rv.reference_range IS NOT NULL OR rv.abnormal_flag IS NOT NULL ON CONFLICT (source_table, source_record_id, evidence_digest) DO NOTHING;
UPDATE clinlims.analyzer_results SET reference_range = CASE WHEN char_length(reference_range) > 80 THEN left(reference_range, 80) ELSE reference_range END, abnormal_flag = CASE WHEN char_length(abnormal_flag) > 40 THEN left(abnormal_flag, 40) ELSE abnormal_flag END WHERE char_length(reference_range) > 80 OR char_length(abnormal_flag) > 40;
UPDATE clinlims.result SET reference_range = CASE WHEN char_length(reference_range) > 80 THEN left(reference_range, 80) ELSE reference_range END, abnormal_flag = CASE WHEN char_length(abnormal_flag) > 40 THEN left(abnormal_flag, 40) ELSE abnormal_flag END WHERE char_length(reference_range) > 80 OR char_length(abnormal_flag) > 40;
ALTER TABLE clinlims.analyzer_results ADD CONSTRAINT ck_analyzer_results_lis97_legacy_evidence_width CHECK ((reference_range IS NULL OR char_length(reference_range) <= 80) AND (abnormal_flag IS NULL OR char_length(abnormal_flag) <= 40)); ALTER TABLE clinlims.result ADD CONSTRAINT ck_result_lis97_legacy_evidence_width CHECK ((reference_range IS NULL OR char_length(reference_range) <= 80) AND (abnormal_flag IS NULL OR char_length(abnormal_flag) <= 40));
